#include <stdio.h>
#include <stdlib.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int n,m; scanf("%d %d", &n, &m);
        int *u = (int*)malloc(m * sizeof(int));
        int *v = (int*)malloc(m * sizeof(int));
        for(int i=0;i<m;i++) scanf("%d %d", &u[i], &v[i]);
        char *used = (char*)calloc(n, sizeof(char));
        int *ans = (int*)malloc(m * sizeof(int));
        int ansCnt = 0;
        for(int i=m-1;i>=0;i--){
            if(!used[u[i]] && !used[v[i]]){
                used[u[i]] = used[v[i]] = 1;
                ans[ansCnt++] = i;
            }
        }
        // sort ascending (answer size ≤ n/2 ≤ 500)
        for(int i=0;i<ansCnt;i++)
            for(int j=i+1;j<ansCnt;j++)
                if(ans[i] > ans[j]){int tmp=ans[i]; ans[i]=ans[j]; ans[j]=tmp;}
        for(int i=0;i<ansCnt;i++){
            if(i) printf(" ");
            printf("%d", ans[i]);
        }
        printf("\n");
        free(u); free(v); free(used); free(ans);
    }
    return 0;
}

