const fs = require('fs');
const data = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = data[idx++];
let outputs = [];
for (let t = 0; t < T; t++) {
  const n = data[idx++];
  const m = data[idx++];
  const edges = new Array(m);
  for (let i = 0; i < m; i++) {
    const u = data[idx++];
    const v = data[idx++];
    edges[i] = [u, v];
  }
  const used = new Array(n).fill(false);
  const ans = [];
  for (let i = m - 1; i >= 0; i--) {
    const [u, v] = edges[i];
    if (!used[u] && !used[v]) {
      used[u] = used[v] = true;
      ans.push(i);
    }
  }
  ans.sort((a, b) => a - b);
  outputs.push(ans.join(' '));
}
